# Reflexion loop skeleton

class ReflexionAgent:
    def __init__(self, llm, tools):
        self.llm = llm
        self.tools = tools
        self.memories = []  # episodic memory of reflections

    def solve(self, task: str, max_attempts=3) -> str:
        for attempt in range(max_attempts):
            # Build context with relevant memories
            context = self._build_context(task)
            answer = self._react_loop(task, context)

            # Evaluate (LLM-as-judge or ground truth check)
            is_correct, feedback = self._evaluate(task, answer)
            if is_correct:
                return answer

            # Generate reflection
            reflection = self._reflect(task, answer, feedback)
            self.memories.append(reflection)

        return self._react_loop(task, self._build_context(task))

    def _build_context(self, task: str) -> str:
        if not self.memories:
            return ""
        return "Previous attempts and reflections:\n" + "\n".join(
            f"- {m}" for m in self.memories[-3:]  # keep last 3
        )

    def _react_loop(self, task: str, context: str) -> str:
        # ponytail: standard ReAct implementation
        pass

    def _evaluate(self, task: str, answer: str) -> tuple:
        # ponytail: checks answer validity; returns (bool, feedback_str)
        pass

    def _reflect(self, task: str, answer: str, feedback: str) -> str:
        prompt = f"""Task: {task}
Your answer: {answer}
Feedback: {feedback}

What went wrong in your reasoning? Be specific.
Reflection:"""
        return self.llm.generate(prompt)

