# Tree-of-Thoughts — simplified beam search over reasoning

def tree_of_thoughts(problem: str, llm, branches=3, depth=3, beam_width=2) -> str:
    """
    Explore multiple reasoning paths, keep the best ones.
    """
    candidates = [""]  # start with empty thought

    for step in range(depth):
        # Generate next thoughts for each candidate
        new_candidates = []
        for candidate in candidates:
            prompt = f"""Problem: {problem}
Current reasoning: {candidate}

Generate {branches} distinct next steps. For each, state what you would do next.
{1}. """
            response = llm.generate(prompt)
            # Parse branches from response
            for line in response.split("\n"):
                if line.strip() and line[0].isdigit():
                    new_candidates.append(candidate + "\n" + line)

        # Evaluate each candidate
        scored = []
        for c in new_candidates:
            eval_prompt = f"""Problem: {problem}
Reasoning so far: {c}

On a scale of 1-10, how promising is this reasoning path?
Score: """
            score_str = llm.generate(eval_prompt)
            try:
                score = int(''.join(filter(str.isdigit, score_str)) or "1")
            except ValueError:
                score = 5
            scored.append((score, c))

        # Keep only the best beam_width candidates
        scored.sort(reverse=True, key=lambda x: x[0])
        candidates = [c for _, c in scored[:beam_width]]

    # Final answer from best candidate
    final_prompt = f"""Problem: {problem}
Reasoning: {candidates[0]}

Based on the above reasoning, provide the final answer:"""
    return llm.generate(final_prompt)

