# Production agent with safety guards

class ProductionAgent:
    def __init__(self, llm, tools, max_cost=0.10):
        self.llm = llm
        self.tools = tools
        self.max_cost = max_cost
        self.total_cost = 0.0
        self.trace = []

    def run(self, task: str) -> str:
        messages = [{"role": "user", "content": task}]

        for step in range(20):
            response = self.llm.generate(messages)
            self.total_cost += self._estimate_cost(messages, response)
            self.trace.append({"step": step, "response": response, "cost": self.total_cost})

            if self.total_cost > self.max_cost:
                return "[Cost limit exceeded]"

            if "Answer:" in response:
                return response.split("Answer:")[-1].strip()

            if "Action:" in response:
                try:
                    result = self._execute_action(response)
                    messages.append({"role": "user", "content": f"Observation: {result}"})
                except Exception as e:
                    messages.append({"role": "user", "content": f"Observation: Error — {str(e)}"})

        return "[Max steps reached]"

    def _execute_action(self, response: str) -> str:
        # Parse action, execute tool, return observation
        action_line = [l for l in response.split("\n") if "Action:" in l][0]
        _, action = action_line.split("Action:", 1)
        tool_name, tool_input = action.strip().split(":", 1)

        if tool_name == "confirm":
            # Safety: pause for human approval
            return self._request_confirmation(tool_input.strip())

        return self.tools[tool_name](tool_input.strip())

    def _request_confirmation(self, action_desc: str) -> str:
        # ponytail: would block and wait for user input
        return f"Confirmed: {action_desc}"

    def _estimate_cost(self, messages, response) -> float:
        # ponytail: approximate; real impl uses tiktoken + model pricing
        total_tokens = sum(len(m.get('content', '').split()) for m in messages)
        return total_tokens * 0.00001
